import{_ as a,o as t,c as s,O as n}from"./chunks/framework.92cbe775.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"en/materials/index.md","filePath":"en/materials/index.md","lastUpdated":1776068451000}'),r={name:"en/materials/index.md"};function i(o,e,d,l,c,p){return t(),s("div",null,e[0]||(e[0]=[n('<div class="brand-page-shell brand-page-shell--materials"><section class="brand-hero"><div><p class="brand-kicker">External Materials</p><h1>Materials Overview</h1><div class="brand-hero__panel"><span class="brand-pill">Presentation Kit</span><strong>ExecGov&#39;s external materials cover the founder story, flagship cases, product positioning, value framing, membership and pricing notes, kickoff options, and delivery background so new readers can decide quickly whether this is worth taking further.</strong><p>The materials are organized by the question a reader is trying to answer so they can enter the right page directly.</p></div><p class="brand-lead"> ExecGov&#39;s external materials currently follow seven main lines: <strong>founder story, flagship cases, product introduction, value framing, membership and pricing notes, kickoff options, and delivery background</strong>. The goal is to complete the positioning judgment first, then move into project-fit and delivery-fit judgment through the shortest reasonable path. </p><p class="brand-lead"> If you look at it from a sales or communication path, the four most stable layers right now are: <strong>the free path</strong>, <strong>lightweight local script-slot expansion</strong>, <strong>the formal team edition with monthly or annual subscription</strong>, and <strong>enterprise delivery or private deployment</strong>. Everything in this section should be explained around those four layers so personal expansion, standard team collaboration, and enterprise project delivery do not get mixed into one story. </p><div class="brand-chip-list"><span class="brand-chip">Founder story</span><span class="brand-chip">Flagship cases</span><span class="brand-chip">Product introduction</span><span class="brand-chip">Value framing</span><span class="brand-chip">Membership and pricing</span><span class="brand-chip">Kickoff options</span><span class="brand-chip">Delivery background</span></div><div class="brand-actions"><a class="cta-button cta-button--brand" href="./why-execgov.html">Why I Am Building ExecGov</a><a class="cta-button" href="./case-studies.html">View Case Studies</a><a class="cta-button" href="./pitch.html">View the Pitch</a><a class="cta-button" href="./value.html">View the Value Framing</a><a class="cta-button" href="./membership-benefits-pricing.html">View Membership and Pricing</a><a class="cta-button" href="./service-packages.html">View Kickoff Options</a></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>EXECGOV // EXTERNAL MATERIALS</span><span>MAT 01</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__key">30s</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__fn">what_it_is</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__ident">why_now</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">3min</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__ident">problem</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__ident">control</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__ident">delivery_value</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">entry</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__fn">pitch</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__fn">value</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__ident">background</span></span></div><div class="matrix-panel__callout">CLEAR MATERIALS FOR REAL DECISIONS</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">scene</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">presales</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">scene</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">demo</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">scene</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">decision</span></span></div></div><article class="brand-hero__panel materials-guide-card"><span class="link-panel-label">How To Use</span><strong>When someone is new to ExecGov, choosing materials by decision stage is faster than reading from top to bottom.</strong><p>This set is not meant to be read cover to cover. It is meant to let different readers jump straight to the page that answers the question they have right now, make a judgment, and then decide whether to continue.</p><div class="materials-guide-list"><div class="materials-guide-item"><span>Start with the problem</span><strong>Read the founder story and the pitch first to understand what problem this is really solving</strong></div><div class="materials-guide-item"><span>Then test credibility</span><strong>Read the flagship cases and the value framing to judge whether the story can support real project conversations</strong></div><div class="materials-guide-item"><span>Prepare to kick off</span><strong>As the conversation becomes real, use kickoff options to understand how phase one can be scoped and closed</strong></div><div class="materials-guide-item"><span>Verify the background</span><strong>When deeper due diligence is needed, move to the delivery background, project history, and public resume pages</strong></div></div></article></div></section><section class="brand-grid brand-grid--three"><article class="brand-card"><p class="brand-kicker">Why</p><h2>Why I Am Building ExecGov</h2><p>Explains what pain I kept seeing, why governance and execution must be discussed together, and why Python scripts are the first landing point.</p></article><article class="brand-card"><p class="brand-kicker">Showroom</p><h2>Case Studies</h2><p>Shows 2-3 end-to-end execution examples that go beyond a hello demo and can be used directly in project conversations.</p></article><article class="brand-card"><p class="brand-kicker">Pitch</p><h2>Pitch</h2><p>Answers what ExecGov is, what problem it solves, and how it differs from a generic chat page or a loose script tool.</p></article><article class="brand-card"><p class="brand-kicker">Value</p><h2>Value Framing</h2><p>Explains efficiency, controllability, governance boundary, and long-term value for business owners, operators, and technical decision makers.</p></article><article class="brand-card"><p class="brand-kicker">Membership</p><h2>Membership and Pricing</h2><p>Separates the free path, local script-slot expansion, formal team subscription, and enterprise delivery so pricing and entry paths do not get tangled.</p></article><article class="brand-card"><p class="brand-kicker">Cooperation</p><h2>Kickoff Options / Service Packages</h2><p>Explains how a project should start, how the first phase should close, and which cooperation pattern is the better fit.</p></article><article class="brand-card"><p class="brand-kicker">Delivery</p><h2>Delivery Background and Project History</h2><p>Answers whether there is real delivery experience behind the platform and whether the work understands access control, release, audit, and handover.</p></article><article class="brand-card"><p class="brand-kicker">Overview</p><h2>Background Overview</h2><p>Summarizes the long-term direction, current scope, and present boundary so new readers can scan quickly.</p></article><article class="brand-card"><p class="brand-kicker">Resume</p><h2>Projects and Resume</h2><p>Provides a more standard resume view, skill stack, representative projects, and public contact information for deeper verification.</p></article></section><section class="brand-card"><p class="brand-kicker">Sales Ladder</p><h2>The four layers of the current commercial narrative</h2><table><thead><tr><th>Layer</th><th>Best for</th><th>How to frame it</th><th>Suggested entry</th></tr></thead><tbody><tr><td>01. Free path</td><td>People touching the platform for the first time</td><td>Let them feel the value first. Do not jump into pricing or complex delivery too early.</td><td><a href="../guide/getting-started.html">Getting Started</a> / <a href="../product/index.html">Product Overview</a></td></tr><tr><td>02. Lightweight expansion</td><td>People already using scripts continuously in their personal space</td><td>This is script-slot expansion, not a formal team subscription.</td><td><a href="./membership-benefits-pricing.html">Membership and Pricing</a></td></tr><tr><td>03. Team edition</td><td>Teams entering multi-user collaboration and formal tenant usage</td><td>Move into the formal monthly or annual team-tenant path, currently carried by the shared-SaaS frontend, without fixing pricing too early on the materials page.</td><td><a href="./membership-benefits-pricing.html">Membership and Pricing</a> / <a href="../product/personal-billing-membership.html">Billing and Membership</a></td></tr><tr><td>04. Enterprise delivery</td><td>Customers who need stronger isolation, intranet deployment, private deployment, or formal project delivery</td><td>Do not use the standard membership narrative. Discuss the scenario, deployment boundary, and delivery boundary directly.</td><td><a href="./service-packages.html">Kickoff Options / Service Packages</a> / <a href="../product/deployment.html">Deployment</a></td></tr></tbody></table></section><section class="brand-card"><p class="brand-kicker">Page Guide</p><h2>Enter by the question you need answered</h2><table><thead><tr><th>Question you are trying to answer</th><th>Recommended page</th><th>What you will find there</th><th>Best for</th></tr></thead><tbody><tr><td>Why is this worth building</td><td><a href="./why-execgov.html">Why I Am Building ExecGov</a></td><td>The origin of the pain, the core judgment, and why this is governance plus execution</td><td>Technical decision makers and first-time readers</td></tr><tr><td>Are there examples strong enough for project conversations</td><td><a href="./case-studies.html">Case Studies</a></td><td>End-to-end examples, governance boundaries, execution chains, and delivery outcomes</td><td>Customers, presales, and technical leads</td></tr><tr><td>What exactly is ExecGov</td><td><a href="./pitch.html">Pitch</a></td><td>Platform position, problem definition, and how it differs from a generic chat system</td><td>First-time readers</td></tr><tr><td>Is it worth moving forward</td><td><a href="./value.html">Value Framing</a></td><td>Efficiency, controllability, governance value, and long-term significance</td><td>Business owners, operators, and technical decision makers</td></tr><tr><td>How should membership and pricing be explained</td><td><a href="./membership-benefits-pricing.html">Membership and Pricing</a></td><td>Separate framing for the free path, script-slot expansion, the formal team subscription path, and enterprise delivery</td><td>Customers, presales, and people guiding free users</td></tr><tr><td>How should a real project begin</td><td><a href="./service-packages.html">Kickoff Options / Service Packages</a></td><td>How phase one can close, what cooperation modes fit, and how startup risk can be reduced</td><td>Customers, project owners, and scenario leads</td></tr><tr><td>Is there real delivery capability behind it</td><td><a href="./founder-profile.html">Delivery Background and Project History</a></td><td>The long-term capability line, project accumulation, and where the platform ability comes from</td><td>Technical leads and project owners</td></tr></tbody></table></section><section class="brand-card"><p class="brand-kicker">Reading Order</p><h2>Suggested path for a first serious read</h2><div class="brand-link-grid"><a class="brand-link-card" href="./why-execgov.html"><span>Step 01</span><strong>Why I Am Building ExecGov</strong><p>Start with the founder story and the source of the pain so you can judge whether the platform grows out of a real problem.</p></a><a class="brand-link-card" href="./case-studies.html"><span>Step 02</span><strong>Case Studies</strong><p>Then read 2-3 end-to-end examples that can be used in real project discussions and judge whether the execution chain is convincing.</p></a><a class="brand-link-card" href="./pitch.html"><span>Step 03</span><strong>Pitch</strong><p>Use it to lock down the platform position and problem definition.</p></a><a class="brand-link-card" href="./value.html"><span>Step 04</span><strong>Value Framing</strong><p>Then judge why this is worth moving forward and where the value comes from.</p></a><a class="brand-link-card" href="./membership-benefits-pricing.html"><span>Step 05</span><strong>Membership and Pricing</strong><p>When the conversation reaches free-path guidance, quoting, or sales discussion, separate the narratives for free usage, expansion, the team edition, and enterprise delivery first.</p></a><a class="brand-link-card" href="./service-packages.html"><span>Step 06</span><strong>Kickoff Options / Service Packages</strong><p>When the conversation is approaching a real project, use this page to understand the cooperation structure and how phase one should close.</p></a><a class="brand-link-card" href="./founder-profile.html"><span>Step 07</span><strong>Delivery Background and Project History</strong><p>Continue by checking delivery credibility and the source of the platform capability.</p></a><a class="brand-link-card" href="../product/index.html"><span>Step 08</span><strong>Product Overview</strong><p>Go deeper into the real capabilities, module structure, and current product mainline.</p></a><a class="brand-link-card" href="../contact.html#lead-form"><span>Step 09</span><strong>Discuss a real scenario</strong><p>Move into real conversation, evaluation, and scenario explanation.</p></a></div></section><section class="brand-card"><p class="brand-kicker">Background Pack</p><h2>Background pages related to delivery credibility</h2><div class="brand-link-grid"><a class="brand-link-card" href="./founder-card.html"><span>Overview</span><strong>Background Overview</strong><p>Best for a quick first-pass judgment on the current capability and scope.</p></a><a class="brand-link-card" href="./founder-profile.html"><span>Background</span><strong>Delivery Background and Project History</strong><p>Best for a deeper look at the long-term mainline, project accumulation, and how the platform formed.</p></a><a class="brand-link-card" href="./resume-public.html"><span>Resume</span><strong>Projects and Resume</strong><p>Best for a more standard view of resume history, skills, and representative projects.</p></a></div></section><section class="brand-card brand-card--cta"><div class="brand-card__row"><div><p class="brand-kicker">Next Step</p><h2>Finish the positioning judgment first, then move into cooperation and delivery judgment</h2><p class="brand-lead">When you are entering real project discussion, prioritize kickoff options and delivery background. If you are still deciding whether the platform position makes sense, start from the pitch and the value framing.</p></div><div class="brand-link-grid brand-link-grid--compact"><a class="brand-link-card" href="./why-execgov.html"><span>Why</span><strong>Why I Am Building ExecGov</strong></a><a class="brand-link-card" href="./case-studies.html"><span>Cases</span><strong>Case Studies</strong></a><a class="brand-link-card" href="./pitch.html"><span>Pitch</span><strong>Pitch</strong></a><a class="brand-link-card" href="./value.html"><span>Value</span><strong>Value Framing</strong></a><a class="brand-link-card" href="./membership-benefits-pricing.html"><span>Pricing</span><strong>Membership and Pricing</strong></a><a class="brand-link-card" href="./service-packages.html"><span>Cooperation</span><strong>Kickoff Options / Service Packages</strong></a><a class="brand-link-card" href="./founder-profile.html"><span>Background</span><strong>Delivery Background and Project History</strong></a></div></div></section></div>',1)]))}const u=a(r,[["render",i]]);export{m as __pageData,u as default};
